class Solution {
public:
    bool isSubsetSum(int n, vector<int>& arr, int target) {
        vector<bool> dp(target + 1, false);
        dp[0] = true;  // Empty subset has sum 0

        for (int i = 0; i < n; i++) {
            int val = arr[i];
            for (int s = target; s >= val; s--) {
                if (dp[s - val]) {
                    dp[s] = true;
                }
            }
        }

        return dp[target];
    }
};

