        dp[0] = True  # Empty subset sum

        for val in arr:
            for s in range(target, val - 1, -1):
                if dp[s - val]:
                    dp[s] = True

        return dp[target]

code.C:
int isSubsetSum(int n, int* arr, int target) {
    int* dp = (int*)calloc(target + 1, sizeof(int));
    if (!dp) return 0;

    dp[0] = 1;  // Empty subset sum

    for (int i = 0; i < n; i++) {
        int val = arr[i];
        for (int s = target; s >= val; s--) {
            if (dp[s - val]) {
                dp[s] = 1;
            }
        }
    }

    int result = dp[target];
    free(dp);
    return result;
}

